503	/// Render one record cell from its flat (un-escaped) text into the exact label
504	/// bytes: single line (escaped) when it fits [`FILL_WIDTH`], otherwise the wrapped
505	/// form — physical lines each prefixed by their `&nbsp;` indent, escaped, and
506	/// terminated by `\l` (trailing `\l` included), per BEHAVIOR.md §3f.
507	///
508	/// Dispatch by cell shape: an info cell (`#t : Rule[…]`) uses the vertical action
509	/// `sep`; a fact / relation cell (`NAME( … )`) uses the greedy argument/tuple fill
510	/// with the delimiter peel. The same entry serves the Term-based path (feed
511	/// [`Fact::render_flat`]) and the pre-rendered-string path (feed the caller's
512	/// already-rendered cell text): the wrap and escape apply identically.
513	pub fn wrap_cell(flat: &str) -> String {
514	    wrap_cell_budget(flat, FILL_WIDTH)
515	}
516	
517	/// Lay a cell's flat text out into physical lines at `budget`, dispatching by
518	/// cell shape: an info cell (`#t : Rule[…]`) uses the vertical action `sep`; a
519	/// fact / relation cell (`NAME( … )`) uses the greedy argument/tuple fill with the
520	/// delimiter peel. Shared by [`wrap_cell_budget`] (which escapes + joins the lines)
521	/// and [`cell_occ`] (which measures them).
522	fn layout_cell(flat: &str, budget: usize) -> Vec<PLine> {
523	    if flat.starts_with('#') && flat.contains('[') {
524	        layout_info(flat, budget)
525	    } else {
526	        layout_fact(flat, budget)
527	    }
528	}
529	
530	/// Render one record cell with an explicit wrap `budget` (BEHAVIOR.md §3f). The
531	/// budget is the cell's share of its record group's [`FILL_WIDTH`] — see
532	/// [`cell_budget`]; a lone cell uses [`FILL_WIDTH`]. An info cell (`#t : Rule[…]`)
533	/// uses the vertical action `sep` (always vertical for ≥ 2 actions); a fact /
534	/// relation cell (`NAME( … )`) uses the greedy argument/tuple fill with the
535	/// delimiter peel. This is the single entry for both the Term-based path (feed
536	/// [`Fact::render_flat`]) and the pre-rendered-string path.
537	pub fn wrap_cell_budget(flat: &str, budget: usize) -> String {
538	    let lines = layout_cell(flat, budget);
539	    if lines.len() == 1 && lines[0].0 == 0 {
540	        return escape_record(&lines[0].1);
541	    }
542	    let mut out = String::new();
543	    for (indent, text) in &lines {
544	        out.push_str(&"&nbsp;".repeat(*indent));
545	        out.push_str(&escape_record(text));
546	        out.push_str("\\l");
547	    }
548	    out
549	}
