66	    pub conclusions: Vec<Fact>,
67	    /// Per-rule fill color (a solver-side hash — a GAP; supplied by the caller).
68	    pub fillcolor: String,
69	    /// `black` on the light MSR palette, `white`/`black` on the role palette.
70	    pub fontcolor: String,
