236	impl GraphNode {
237	    /// The designated last timepoint `#last` (BEHAVIOR.md §3d/§6).
238	    pub fn last() -> Self {
239	        GraphNode::Temporal { var: "last".into() }
240	    }
241	    /// A record node from a [`RecordSpec`], if this node is one.
242	    fn record_spec(&self) -> Option<RecordSpec> {
243	        match self {
244	            GraphNode::Rule(r) => Some(r.spec()),
245	            GraphNode::RawRule(r) => Some(r.spec()),
246	            _ => None,
247	        }
248	    }
249	}
