348	/// Build the DOT [`Graph`] for a [`System`]: allocate ids in emission order (so id
349	/// order == file order), emit free (non-clustered) node statements at the top
350	/// level, then the `cluster_…` subgraph blocks (role records, grouped by cluster
351	/// label in first-appearance order), then edges, then the legend sink-block + its
352	/// invis edges. Header is inferred from roles (§4).
353	pub fn generate(sys: &System) -> Graph {
354	    let mut alloc = NodeIdAllocator::new();
355	    let mut resolved: Vec<Resolved> = Vec::with_capacity(sys.nodes.len());
356	
357	    // Free top-level node statements, in emission order.
358	    let mut free: Vec<Stmt> = Vec::new();
359	    // Clusters: label -> (color, record statements), with first-appearance order.
360	    let mut cluster_order: Vec<String> = Vec::new();
361	    let mut clusters: std::collections::HashMap<String, (String, Vec<Stmt>)> =
362	        std::collections::HashMap::new();
363	
364	    // Pass 1: allocate ids and build node statements in emission order. A clustered
365	    // record's statement is routed into its cluster bucket; everything else is free.
366	    for node in &sys.nodes {
367	        if let Some(spec) = node.record_spec() {
368	            let ids = alloc.record(spec.cell_count());
369	            let mut it = ids.ports.into_iter();
370	            let ports_prem: Vec<String> = (0..spec.premises.len()).map(|_| it.next().unwrap()).collect();
371	            let port_info = it.next().unwrap();
372	            let ports_concl: Vec<String> =
373	                (0..spec.conclusions.len()).map(|_| it.next().unwrap()).collect();
374	            let rec = build_record(&spec, &ports_prem, &port_info, &ports_concl);
375	            let stmt = Stmt::Node(Node::record(ids.node.clone(), rec));
376	            match &spec.cluster {
377	                Some(c) => {
378	                    let entry = clusters.entry(c.label.clone()).or_insert_with(|| {
379	                        cluster_order.push(c.label.clone());
380	                        (c.color.clone(), Vec::new())
381	                    });
382	                    entry.1.push(stmt);
383	                }
384	                None => free.push(stmt),
385	            }
386	            resolved.push(Resolved::Record { ports_prem, ports_concl, node: ids.node });
387	            continue;
388	        }
389	        let id = alloc.node();
390	        let stmt = match node {
391	            GraphNode::Knowledge { term, temporal } => {
392	                let label = format!("!KU( {} ) @ #{}", term, temporal);
393	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "gray")))
394	            }
395	            GraphNode::Action { fact, temporal } => {
396	                let label = format!("{} @ #{}", fact, temporal);
397	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "darkblue")))
398	            }
399	            GraphNode::Compressed { temporal, rule } => {
400	                let label = format!("#{} : {}", temporal, rule);
401	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(label)))
402	            }
403	            GraphNode::Temporal { var } => {
404	                Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(format!("#{}", var))))
405	            }
406	            GraphNode::OpenTarget { node_var, premise_index } => {
407	                Stmt::Node(Node::shaped(id.clone(), Shaped::invtrapezium(node_var, *premise_index)))
408	            }
409	            GraphNode::Shaped { label, shape, color } => Stmt::Node(Node::shaped(
410	                id.clone(),
411	                Shaped { label: label.clone(), shape: shape.clone(), color: color.clone() },
412	            )),
413	            GraphNode::Rule(_) | GraphNode::RawRule(_) => unreachable!("records handled above"),
414	        };
415	        free.push(stmt);
416	        resolved.push(Resolved::Node(id));
417	    }
418	
419	    // Assemble: free nodes, then clusters (first-appearance order), then edges.
420	    let mut g = Graph::new(Header::Simple);
421	    for s in free {
422	        g.push(s);
423	    }
424	    for label in &cluster_order {
425	        let (color, body) = clusters.remove(label).unwrap();
426	        g.push(Stmt::Cluster(Cluster { label: label.clone(), color, body }));
427	    }
428	
429	    // Pass 2: edges.
430	    for e in &sys.edges {
431	        let src = endpoint(&resolved, e.src);
432	        let dst = endpoint(&resolved, e.dst);
433	        g.push(Stmt::Edge(Edge { src, dst, attrs: e.style.attrs() }));
434	    }
435	
436	    // Pass 3: legend sink-block, then its invis edges (observed order).
437	    if let Some(html) = &sys.legend_html {
438	        if !html.is_empty() {
439	            let legend_id = alloc.node();
440	            let block = RankBlock {
441	                rank: "sink".into(),
442	                body: vec![Stmt::Node(Node::plain(legend_id.clone(), html.clone()))],
443	            };
444	            g.push(Stmt::RankBlock(block));
445	            for (from, ()) in &sys.legend_edges {
446	                let src = endpoint(&resolved, *from);
447	                g.push(Stmt::Edge(Edge {
448	                    src,
449	                    dst: EndPoint::node(legend_id.clone()),
450	                    attrs: EdgeStyle::Invis.attrs(),
451	                }));
452	            }
453	        }
454	    }
455	
456	    g.set_inferred_header();
457	    g
458	}
459	
460	/// Assemble a record node's model from a [`RecordSpec`] and its allocated ports.
461	/// Empty premise / conclusion groups are dropped; the info group is always kept
462	/// (matches the observed group structure). Each group's cells share the record
463	/// wrap budget: within a premise or conclusion group a cell wraps when its flat
464	/// width exceeds `max(87 − Σ other cell flats, 20)` (BEHAVIOR.md §3f); the info
465	/// cell is its own single-cell group (budget 87). Cell text is wrapped and escaped
466	/// by [`wrap_cell_budget`].
467	fn build_record(spec: &RecordSpec, ports_prem: &[String], port_info: &str, ports_concl: &[String]) -> Record {
468	    let mut columns: Vec<Vec<Cell>> = Vec::new();
469	    if !spec.premises.is_empty() {
470	        columns.push(group_cells(&spec.premises, ports_prem));
471	    }
472	    columns.push(vec![Cell::new(port_info, wrap_cell(&spec.info))]);
473	    if !spec.conclusions.is_empty() {
474	        columns.push(group_cells(&spec.conclusions, ports_concl));
475	    }
476	    Record {
477	        columns,
478	        fillcolor: spec.fillcolor.clone(),
479	        fontcolor: spec.fontcolor.clone(),
480	        role: Role(spec.role.clone()),
481	    }
482	}
483	
484	/// Wrap every cell of one record group (all premises together, or all conclusions
485	/// together), sharing the group's [`FILL_WIDTH`] budget (BEHAVIOR.md §3f).
486	///
487	/// Two budgets per cell, both derived only from the group's cell widths:
488	///  * the **wrap TRIGGER** (does a cell break at all) is the flat-sum budget
489	///    [`cell_budget`] = `max(87 − Σ other cells' flat widths, 20)`: a cell wraps
490	///    iff its flat width exceeds this. Byte-exact away from the ±1 `fits` boundary
491	///    (matches 99.5 % of corpus prem/concl cells).
492	///  * the **FILL width** used *once* a cell wraps is wider than the flat-sum
493	///    budget, because a sibling that itself wraps occupies only the width it is
494	///    ALLOCATED, not its full flat width. So a wide cell packs more elements per
495	///    line than the flat-sum budget predicts — the observed "one more element" in a
496	///    group like `[Ack 25, Big 68, Out 11]`, where `Big`'s effective fill budget is
497	///    `87 − 20 − 11 = 56` (`Ack` wraps and is allocated 20), not `87 − 25 − 11 = 51`.
498	///
499	/// The fill budgets come from a **smallest-flat-first** allocation that reproduces
500	/// the greedy pretty-printer's coupling. Process cells in increasing flat width;
501	/// each cell's fill budget is `max(87 − Σ others' allocations, 20)`, where an
502	/// already-processed sibling contributes `min(flat, its own budget)` (a wrapping
503	/// sibling occupies just its budget) and an un-processed (wider) sibling still
504	/// contributes its full flat width. So the narrow cells are packed tight first and
505	/// the widest cell expands into the room their allocations leave — e.g. `Ack`, seen
506	/// before `Big` is placed, faces `Big`'s full flat 68 and is squeezed to 20, while
507	/// `Big`, placed last, sees `Ack`'s allocation 20 and gets 56.
508	fn group_cells(flat_cells: &[String], ports: &[String]) -> Vec<Cell> {
509	    let widths: Vec<usize> = flat_cells.iter().map(|t| t.chars().count()).collect();
510	    let n = flat_cells.len();
511	    let trigger: Vec<usize> = (0..n).map(|i| cell_budget(&widths, i)).collect();
512	
513	    // Smallest-flat-first fill-budget allocation. `alloc[j]` starts at the flat
514	    // width and becomes `min(flat, budget)` once cell j is processed.
515	    let mut order: Vec<usize> = (0..n).collect();
516	    order.sort_by_key(|&i| widths[i]); // stable: ties keep group order
517	    let mut alloc = widths.clone();
518	    let mut fill = vec![0usize; n];
519	    for &i in &order {
520	        let others: usize = (0..n).filter(|&j| j != i).map(|j| alloc[j]).sum();
521	        let budget = FILL_WIDTH.saturating_sub(others).max(MIN_CELL_BUDGET);
522	        fill[i] = budget;
523	        alloc[i] = widths[i].min(budget);
524	    }
525	
526	    flat_cells
527	        .iter()
528	        .zip(ports)
529	        .enumerate()
530	        .map(|(i, (text, p))| {
531	            // The flat-sum trigger decides whether the cell breaks; the fill budget
532	            // (≥ the trigger budget) governs how it packs once it does. Capping at
533	            // `flat − 1` keeps a flat-sum-triggered break even in the rare case the
534	            // wider fill budget alone would leave the cell on one line.
535	            let budget = if widths[i] <= trigger[i] {
536	                trigger[i]
537	            } else {
538	                fill[i].min(widths[i] - 1).max(trigger[i])
539	            };
540	            Cell::new(p.clone(), wrap_cell_budget(text, budget))
541	        })
542	        .collect()
543	}
544	
545	/// Resolve an [`EndRef`] to a serializer [`EndPoint`] using the id/port map.
546	fn endpoint(resolved: &[Resolved], r: EndRef) -> EndPoint {
547	    match r {
548	        EndRef::Whole(n) => EndPoint::node(resolved[n].node_id().to_string()),
549	        EndRef::Conclusion(n, c) => {
550	            if let Resolved::Record { node, ports_concl, .. } = &resolved[n] {
551	                EndPoint::port(node.clone(), ports_concl[c].clone())
552	            } else {
553	                EndPoint::node(resolved[n].node_id().to_string())
554	            }
555	        }
556	        EndRef::Premise(n, p) => {
557	            if let Resolved::Record { node, ports_prem, .. } = &resolved[n] {
558	                EndPoint::port(node.clone(), ports_prem[p].clone())
559	            } else {
560	                EndPoint::node(resolved[n].node_id().to_string())
561	            }
562	        }
563	    }
564	}
